function Education() {
  const educationServices = [
    {
      title: "Math Tutoring",
      description:
        "Get support with math lessons, exercises, and homework from community volunteers.",
    },
    {
      title: "English Practice",
      description:
        "Practice speaking, reading, and writing English in a friendly learning environment.",
    },
    {
      title: "Programming Help",
      description:
        "Learn basic coding concepts, solve programming exercises, and improve your technical skills.",
    },
    {
      title: "Online Learning Support",
      description:
        "Receive help using online learning platforms, digital resources, and study tools.",
    },
  ];

  return (
    <section className="page-section">
      <div className="page-header">
        <h1>Education Help</h1>

        <p>
          Education Help connects students with community members who can support
          learning, homework, language practice, and digital study skills.
        </p>
      </div>

      <section className="cards">
        {educationServices.map((service, index) => (
          <div className="card" key={index}>
            <h3>{service.title}</h3>
            <p>{service.description}</p>
          </div>
        ))}
      </section>
    </section>
  );
}

export default Education;
